```javascript
async function obtenirMeteo(nomVille, cleAPI) {
  const url = `https://api.openweathermap.org/data/2.5/weather?q=${encodeURIComponent(nomVille)}&appid=${cleAPI}&units=metric`;

  try {
    const reponse = await fetch(url);

    if (!reponse.ok) {
      if (reponse.status === 404) {
        throw new Error(`Ville "${nomVille}" non trouvée. Vérifiez le nom.`);
      } else if (reponse.status === 401) {
        throw new Error('Clé API invalide. Vérifiez votre clé.');
      } else {
        throw new Error(`Erreur HTTP ${reponse.status}: ${reponse.statusText}`);
      }
    }

    const donnees = await reponse.json();

    return {
      ville: donnees.name,
      temperature: Math.round(donnees.main.temp),
      humidite: donnees.main.humidity,
      description: donnees.weather[0].description,
      icone: donnees.weather[0].icon
    };
  } catch (erreur) {
    if (erreur.name === 'TypeError' && erreur.message.includes('fetch')) {
      throw new Error('Problème réseau. Vérifiez votre connexion internet.');
    }
    throw erreur;
  }
}

// Exemple d'utilisation
obtenirMeteo('Yaounde', 'ma_cle_api')
  .then(meteo => console.log(`Il fait ${meteo.temperature}°C à ${meteo.ville} avec ${meteo.humidite}% d'humidité.`))
  .catch(err => console.error(err.message));
```

