function afficherMeteo(meteo) {
  let message = `🌍 Météo pour ${meteo.ville} :\n`;
  message += `🌡️ Température : ${meteo.temperature}°C\n`;
  message += `💧 Humidité : ${meteo.humidite}%\n`;
  message += `☁️ Conditions : ${meteo.description}`;

  // Conseils pratiques pour agriculteurs
  if (meteo.humidite > 80) {
    message += `\n⚠️ Attention : forte humidité, risque de moisissures.`;
  } else if (meteo.humidite < 40) {
    message += `\n⚠️ Attention : faible humidité, besoin d'irrigation.`;
  }

  if (meteo.description.includes('pluie') || meteo.description.includes('averse')) {
    message += `\n🌧️ Arrosage naturel : réduire l'irrigation.`;
  }

  console.log(message);
  return message;
}

// Exemple avec données fictives
afficherMeteo({
  ville: 'Bafoussam',
  temperature: 22,
  humidite: 85,
  description: 'pluie modérée'
});
```

```javascript
const cacheMeteo = new Map();

function estCacheValide(timestamp) {
  const maintenant = Date.now();
  const dureeCache = 10 * 60 * 1000; // 10 minutes en millisecondes
  return (maintenant - timestamp) < dureeCache;
}

async function obtenirMeteoAvecCache(nomVille, cleAPI) {
  const villeNormalisee = nomVille.toLowerCase().trim();
  const cacheEntry = cacheMeteo.get(villeNormalisee);

  // Vérifier si le cache existe et est valide
  if (cacheEntry && estCacheValide(cacheEntry.timestamp)) {
    console.log(`📦 Utilisation des données mises en cache pour ${nomVille}`);
    return cacheEntry.donnees;
  }

  // Si cache invalide ou inexistant, faire la requête
  console.log(`🌐 Récupération des données fraîches pour ${nomVille}`);

  try {
    const donnees = await obtenirMeteo(nomVille, cleAPI);

    // Stocker dans le cache avec timestamp
    cacheMeteo.set(villeNormalisee, {
      donnees: donnees,
      timestamp: Date.now()
    });

    return donnees;
  } catch (erreur) {
    // En cas d'erreur, essayer de retourner des données en cache même expirées
    if (cacheEntry && cacheEntry.donnees) {
      console.warn(`⚠️ Erreur de récupération. Utilisation des données expirées pour ${nomVille}`);
      return cacheEntry.donnees;
    }
    throw erreur;
  }
}

// Fonction pour vider le cache d'une ville spécifique
function viderCache(ville) {
  if (ville) {
    cacheMeteo.delete(ville.toLowerCase().trim());
  } else {
    cacheMeteo.clear(); // Vider tout le cache
  }
}

// Exemple d'utilisation
obtenirMeteoAvecCache('Douala', 'ma_cle_api')
  .then(meteo => afficherMeteo(meteo))
  .catch(err => console.error(err.message));
```

Explication : Ce mécanisme utilise une Map pour stocker les données météo associées à un timestamp. Lors d'une requête, on vérifie si les données en cache existent et si elles datent de moins de 10 minutes. Si c'est le cas, on les retourne sans appeler l'API. Sinon, on appelle l'API, on met à jour le cache et on retourne les nouvelles données. En cas d'erreur réseau, on peut même retourner des données expirées comme fallback.
